const body = $input.first().json.body || {};
const email = (body.email || '').trim().toLowerCase();
const listUuid = (body.l || '').trim();

function emailBase({ bg, headerBg, headerText, headerAccent, bodyBg, textColor, mutedColor, borderColor, ctaBg, ctaText, projectName, bullets, url, email, unsubUrl }) {
  const preheader = "You're subscribed \u2014 here's what's coming your way.";
  const bulletsHtml = bullets.map(b =>
    '<tr><td style="padding:4px 0 4px 0"><span style="display:inline-block;width:20px;color:' + ctaBg + '">\u203a</span><span style="font-size:14px;color:' + textColor + ';line-height:1.7">' + b + '</span></td></tr>'
  ).join('');

  return '<!DOCTYPE html>' +
'<html lang="en">' +
'<head>' +
'<meta charset="utf-8">' +
'<meta name="viewport" content="width=device-width,initial-scale=1">' +
'<title>Welcome to ' + projectName + '</title>' +
'</head>' +
'<body style="margin:0;padding:0;background:' + bg + ';font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\',Helvetica,sans-serif">' +
'<div style="display:none;max-height:0;overflow:hidden;mso-hide:all">' + preheader + '\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c\u200c</div>' +
'<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:' + bg + ';padding:40px 16px">' +
'<tr><td align="center">' +
'<table width="100%" cellpadding="0" cellspacing="0" border="0" style="max-width:560px">' +
'<tr><td style="background:' + headerBg + ';border-radius:12px 12px 0 0;padding:40px 40px 36px">' +
'<p style="margin:0 0 10px;font-size:10px;font-weight:700;letter-spacing:4px;text-transform:uppercase;color:' + headerAccent + '">' + projectName + '</p>' +
'<h1 style="margin:0 0 8px;font-size:30px;font-weight:800;color:' + headerText + ';line-height:1.15">You\'re in.</h1>' +
'<p style="margin:0;font-size:15px;color:' + headerAccent + ';line-height:1.5;opacity:0.85">Your subscription is confirmed.</p>' +
'</td></tr>' +
'<tr><td style="background:' + bodyBg + ';padding:32px 40px 28px;border-left:1px solid ' + borderColor + ';border-right:1px solid ' + borderColor + '">' +
'<p style="margin:0 0 24px;font-size:15px;color:' + textColor + ';line-height:1.8">Hi \u2014 thanks for subscribing. Here\'s what you\'ll get:</p>' +
'<table cellpadding="0" cellspacing="0" border="0" style="margin:0 0 28px">' + bulletsHtml + '</table>' +
'<p style="margin:0 0 28px;font-size:13px;color:' + mutedColor + ';line-height:1.7">Delivered to <strong style="color:' + textColor + '">' + email + '</strong> \u2014 one email per week, no spam.</p>' +
'<table cellpadding="0" cellspacing="0" border="0"><tr><td style="background:' + ctaBg + ';border-radius:8px">' +
'<a href="' + url + '" style="display:block;padding:14px 32px;color:' + ctaText + ';text-decoration:none;font-size:14px;font-weight:700;letter-spacing:0.3px">Visit ' + projectName + ' \u2192</a>' +
'</td></tr></table>' +
'</td></tr>' +
'<tr><td style="background:' + bg + ';border:1px solid ' + borderColor + ';border-top:none;border-radius:0 0 12px 12px;padding:20px 40px">' +
'<p style="margin:0;font-size:11px;color:' + mutedColor + ';line-height:1.9">' +
projectName + ' is part of <a href="https://theunnamedroads.com" style="color:' + mutedColor + ';text-decoration:underline">The Unnamed Roads</a>.' +
' \u00b7 ' +
'<a href="' + unsubUrl + '" style="color:' + mutedColor + ';text-decoration:underline">Unsubscribe</a>' +
' \u00b7 ' +
'<a href="' + unsubUrl + '" style="color:' + mutedColor + ';text-decoration:underline">Manage preferences</a>' +
'</p>' +
'</td></tr>' +
'</table>' +
'</td></tr>' +
'</table>' +
'</body></html>';
}

const UNSUB = "https://list.theunnamedroads.com/subscription/manage";

const projects = {
  'e7f38861-4bc4-448d-85ae-376e7f7c2fb0': {
    name: 'The Unnamed Roads',
    bullets: [
      'Weekly notes on AI systems, solo building, and the roads worth taking',
      'Real talk on what\'s working \u2014 and what\'s breaking \u2014 in practice',
      'No hype, no fluff. Just signal.'
    ],
    url: 'https://theunnamedroads.com',
    style: { bg:'#0a0a0a', headerBg:'#111', headerText:'#f5f5f5', headerAccent:'#818cf8', bodyBg:'#111', textColor:'#c8c8c8', mutedColor:'#555', borderColor:'#222', ctaBg:'#6366f1', ctaText:'#fff' }
  },
  '149f7d0c-5959-409f-9043-d26cf920df84': {
    name: 'The Hockey Brain',
    bullets: [
      'Data-driven analysis of NHL performance, scouting, and team strategy',
      'Weekly deep dives \u2014 the numbers that actually explain the game',
      'No hot takes. Just the metrics that matter.'
    ],
    url: 'https://thehockeybrain.com',
    style: { bg:'#f0f9ff', headerBg:'#0c4a6e', headerText:'#ffffff', headerAccent:'#7dd3fc', bodyBg:'#ffffff', textColor:'#1e3a5f', mutedColor:'#94a3b8', borderColor:'#bae6fd', ctaBg:'#0ea5e9', ctaText:'#fff' }
  },
  '8a52a36a-abc5-4e76-84d4-96c5f3000826': {
    name: 'The Agent Fabric',
    bullets: [
      'AI agents in production \u2014 real architectures, real failures, hard-won lessons',
      'Weekly breakdowns of what actually works in multi-agent systems',
      'Skip the hype. Build better agents.'
    ],
    url: 'https://theagentfabric.com',
    style: { bg:'#060d1f', headerBg:'#0b1020', headerText:'#f1f5f9', headerAccent:'#93c5fd', bodyBg:'#0d1526', textColor:'#cbd5e1', mutedColor:'#475569', borderColor:'#1e2d45', ctaBg:'#3b82f6', ctaText:'#fff' }
  },
  'dc3c277d-d37a-4753-8b4c-27e7b1755af8': {
    name: 'The Atomic Network',
    bullets: [
      'Cross-chain protocols, decentralized AI, and Web3 infrastructure \u2014 what matters',
      'Weekly signal from the edges of the decentralized internet',
      'Hyperlocal. High signal. Weekly.'
    ],
    url: 'https://theatomicnetwork.com',
    style: { bg:'#f8fafc', headerBg:'#1e3a8a', headerText:'#ffffff', headerAccent:'#93c5fd', bodyBg:'#ffffff', textColor:'#1e293b', mutedColor:'#94a3b8', borderColor:'#e2e8f0', ctaBg:'#2563eb', ctaText:'#fff' }
  },
  '9725bc88-729a-4344-99d2-5866a2d7b26b': {
    name: 'The Print Route',
    bullets: [
      'Smart print logistics, provider networks, and automation workflows',
      'Weekly updates on fulfilment routing, cost optimisation, and industry moves',
      'Built for founders and operators in the print supply chain.'
    ],
    url: 'https://theprintroute.com',
    style: { bg:'#0f172a', headerBg:'#1e1b4b', headerText:'#f1f5f9', headerAccent:'#a5b4fc', bodyBg:'#1e293b', textColor:'#cbd5e1', mutedColor:'#475569', borderColor:'#334155', ctaBg:'#4f46e5', ctaText:'#fff' }
  },
  '55248e17-408c-4ede-ac40-189daabbcb0f': {
    name: 'Emil Ingemark Karlsson',
    bullets: [
      'Notes on data engineering, AI, and automation \u2014 what works and what breaks',
      'Projects, experiments, and lessons from building in public',
      'Honest. Practical. Weekly.'
    ],
    url: 'https://emilingemarkarlsson.com',
    style: { bg:'#f9fafb', headerBg:'#111827', headerText:'#f9fafb', headerAccent:'#9ca3af', bodyBg:'#ffffff', textColor:'#374151', mutedColor:'#9ca3af', borderColor:'#e5e7eb', ctaBg:'#111827', ctaText:'#fff' }
  }
};

const p = projects[listUuid] || projects['e7f38861-4bc4-448d-85ae-376e7f7c2fb0'];

const thankYouHtml = '<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"><title>You\'re in</title><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:-apple-system,sans-serif;background:#0a0a0a;color:#f5f5f5;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px}.card{max-width:480px;text-align:center}.icon{font-size:48px;margin-bottom:24px}h1{font-size:28px;font-weight:700;margin-bottom:12px}p{color:#888;line-height:1.7;margin-bottom:24px;font-size:15px}a{color:' + p.style.ctaBg + ';text-decoration:none;border-bottom:1px solid ' + p.style.ctaBg + '40;padding-bottom:2px}</style></head><body><div class="card"><div class="icon">\u2709\ufe0f</div><h1>You\'re in.</h1><p>' + p.bullets[0] + '</p><a href="' + p.url + '">\u2190 Back to ' + p.name + '</a></div></body></html>';

return [{json: {
  email,
  listUuid,
  projectName: p.name,
  projectUrl: p.url,
  thankYouHtml,
  welcomeHtml: emailBase({ ...p.style, projectName: p.name, bullets: p.bullets, url: p.url, email, unsubUrl: UNSUB }),
  welcomeSubject: "You're in \u2014 welcome to " + p.name
